function solve(nums, k) {
    const N = nums.length;
    const INF = Number.MAX_SAFE_INTEGER;

    if (k === 0) return 0;
    if (k > Math.floor(N / 2)) return -1;

    // 1. Precalculate W[i]: the minimum cost to make nums[i] a peak, assuming neighbors are not peaks.
    const W = new Array(N);
    for (let i = 0; i < N; i++) {
        const prev = nums[(i - 1 + N) % N];
        const next = nums[(i + 1) % N];

        // Required increment C_i must satisfy:
        // nums[i] + C_i > prev  => C_i >= prev - nums[i] + 1
        // nums[i] + C_i > next  => C_i >= next - nums[i] + 1
        const cost1 = Math.max(0, prev - nums[i] + 1);
        const cost2 = Math.max(0, next - nums[i] + 1);
        W[i] = Math.max(cost1, cost2);
    }

    let minTotalCost = INF;

    /**
     * Solves the linear MWIS problem for a segment [start, end].
     * DP[i][j][s]: Min cost selecting j peaks from indices {start, ..., i}.
     * s=0: i is NOT selected.
     * s=1: i IS selected.
     * @param {number} start Inclusive start index
     * @param {number} end Inclusive end index
     * @returns {Array<Array<number>>} DP table: DP[i][j] = [cost_s0, cost_s1]
     */
    const solveLinearDP = (start, end) => {
        if (start > end) return [];

        const rangeLength = end - start + 1;
        const maxPeaks = Math.floor(rangeLength / 2);

        // DP array dimensions: (rangeLength) x (maxPeaks + 1) x 2
        // We map original index i to DP index d = i - start.
        const DP = Array(rangeLength).fill(0).map(() => 
            Array(maxPeaks + 1).fill(0).map(() => [INF, INF])
        );

        // Base Case: i = start (DP index d=0)
        // 1. Not selected (j=0, s=0)
        DP[0][0][0] = 0;
        // 2. Selected (j=1, s=1)
        DP[0][1][1] = W[start];

        // Transition
        for (let d = 1; d < rangeLength; d++) {
            const i = start + d; // Original index i

            for (let j = 0; j <= maxPeaks; j++) {

                // --- State 0: i is NOT selected ---
                // Can come from i-1 selected or not selected.
                DP[d][j][0] = Math.min(DP[d - 1][j][0], DP[d - 1][j][1]);

                // --- State 1: i IS selected ---
                // Must come from i-1 NOT selected.
                if (j >= 1) {
                    const cost_i = W[i];
                    // DP[d-1][j-1][0] must be finite
                    if (DP[d - 1][j - 1][0] !== INF) {
                        DP[d][j][1] = DP[d - 1][j - 1][0] + cost_i;
                    }
                }
            }
        }
        return DP;
    };

    // --- Case A: Index 0 is NOT chosen. Analyze segment [1, N-1]. ---
    if (N > 1) {
        const DP_A = solveLinearDP(1, N - 1);
        const N_prime = N - 1;
        const maxJ_A = Math.floor(N_prime / 2);

        // Result A: Min cost achieving >= K peaks
        let costA = INF;
        for (let j = k; j <= maxJ_A; j++) {
            if (DP_A[N_prime - 1][j][0] !== INF || DP_A[N_prime - 1][j][1] !== INF) {
                costA = Math.min(costA, DP_A[N_prime - 1][j][0], DP_A[N_prime - 1][j][1]);
            }
        }
        minTotalCost = Math.min(minTotalCost, costA);
    }


    // --- Case B: Index 0 IS chosen. Analyze segment [2, N-2]. ---
    if (N >= 3) {
        // Index 0 contributes W[0] cost and counts as 1 peak.
        const C0 = W[0];

        // The segment runs from index 2 up to N-2.
        if (N - 2 >= 2) {
            const DP_B = solveLinearDP(2, N - 2);
            const N_double_prime = N - 2;
            const maxJ_B = Math.floor((N_double_prime - 2 + 1) / 2); // Max peaks in [2, N-2]

            // We need j_segment + 1 >= K, so j_segment >= K - 1
            const requiredJ = Math.max(0, k - 1);

            let costB = INF;

            for (let j = requiredJ; j <= maxJ_B; j++) {
                if (DP_B[N_double_prime - 2][j][0] !== INF || DP_B[N_double_prime - 2][j][1] !== INF) {
                    const segmentCost = Math.min(DP_B[N_double_prime - 2][j][0], DP_B[N_double_prime - 2][j][1]);
                    costB = Math.min(costB, C0 + segmentCost);
                }
            }
            minTotalCost = Math.min(minTotalCost, costB);
        }
    }

    return minTotalCost === INF ? -1 : minTotalCost;
